// @kern-source: status:369
const CesarStatusStrip = React.memo(function CesarStatusStrip({ cesarId, confidence, spinner, engines, startTime, streamSnippet, isActive, planModeQueued, autoModeQueued, activePlanState, activePlan, scoreboard, rationale }: { cesarId:string; confidence?:number|null; spinner:{ message: string; engineId?: string } | null; engines:EngineProgress[]|null; startTime:number; streamSnippet?:{ engineId: string; line: string } | null; isActive:boolean; planModeQueued?:boolean; autoModeQueued?:boolean; activePlanState?:string|null; activePlan?:any; scoreboard?:Scoreboard|null; rationale?:ModeRationale|null }) {
  // Ink-safe setter: bridges microtask → macrotask for reliable repaints
  function __inkSafe<T>(setter: React.Dispatch<React.SetStateAction<T>>): React.Dispatch<React.SetStateAction<T>> {
    return (value) => setTimeout(() => setter(value), 0);
  }

  const [now, _setNowRaw] = useState<number>(Date.now());
  const setNow = useMemo(() => __inkSafe(_setNowRaw), [_setNowRaw]);

  useEffect(() => {
    if (!(isActive)) return;
    const _animId = setInterval(() => {
      setNow(Date.now());
    }, 1000);
    return () => clearInterval(_animId);
  }, [isActive]);

  const planGauge = buildPlanPhaseGauge(activePlan, 12);
  // Plan badge (shared between idle and active)
  const hasPlan = planModeQueued || autoModeQueued || (activePlanState && ['planning', 'awaiting_approval', 'running', 'paused'].includes(activePlanState));
  let planLabel = '';
  if (planModeQueued) planLabel = 'ready';
  else if (autoModeQueued) planLabel = 'auto';
  else if (activePlanState === 'planning') planLabel = 'thinking';
  else if (activePlanState === 'awaiting_approval') planLabel = 'review';
  else if (activePlanState === 'running') planLabel = 'executing';
  else if (activePlanState === 'paused') planLabel = 'paused';

  // Idle: single dimmed line (no colored nesting issues)
  if (!isActive) {
    const confPart = (confidence !== null && confidence !== undefined) ? ` ${confidence}%` : '';
    return (
      <Box paddingTop={0} flexDirection="column">
        <Text>
          {hasPlan ? <><Text color={autoModeQueued ? '#f97316' : '#c084fc'} bold>{`\u25c8 ${planLabel.toUpperCase()}`}</Text><Text dimColor>{' \u2502 '}</Text></> : null}
          <Text dimColor>{'\u25c6 '}{cesarId}{confPart}{' \u2502 idle'}</Text>
        </Text>
        {planGauge.visible ? (
          <Text>
            <Text color={planGauge.color} bold>{'PLAN '}{planGauge.shortId}</Text>
            <Text dimColor>{' \u00b7 '}{planGauge.label}{' '}</Text>
            <Text color={planGauge.color}>{planGauge.bar}</Text>
            <Text dimColor>{' '}{planGauge.pct}{'% \u00b7 phase: '}{planGauge.phase}</Text>
            {planGauge.current ? <Text dimColor>{' \u00b7 '}{planGauge.current}</Text> : null}
            {planGauge.failed > 0 ? <Text color="#ef4444">{' \u00b7 '}{planGauge.failed}{' failed'}</Text> : null}
          </Text>
        ) : null}
      </Box>
    );
  }

  // Active: full colored strip
  const cesarColor = color256toHex(ENGINE_COLORS[cesarId] ?? 124);

  // Confidence badge with tier coloring
  let confStr = '';
  let confColor = '#6b7280';
  if (confidence !== null && confidence !== undefined) {
    confStr = ` ${confidence}%`;
    confColor = confidence >= 96 ? '#4ade80' : confidence >= 88 ? '#fbbf24' : confidence >= 72 ? '#f97316' : '#ef4444';
  }

  // Activity segment
  let activityStr = 'working';
  if (spinner) {
    const msg = spinner.message.replace(/\u2026$/, '').trim();
    activityStr = msg.length > 50 ? msg.slice(0, 50) + '\u2026' : msg;
  }

  // Elapsed time (from operation start, not last activity)
  let elapsedStr = '';
  if (startTime > 0) {
    const elapsed = Math.max(0, Math.floor((now - startTime) / 1000));
    if (elapsed > 0) {
      const mins = Math.floor(elapsed / 60);
      const secs = elapsed % 60;
      elapsedStr = mins > 0 ? ` ${mins}m ${secs}s` : ` ${elapsed}s`;
    }
  }

  // Engine dots
  const engineDots: React.ReactNode[] = [];
  if (engines && engines.length > 0) {
    for (const eng of engines) {
      const ec = color256toHex(ENGINE_COLORS[eng.id] ?? 124);
      const icon = eng.done ? '\u2713' : eng.failed ? '\u2717' : '\u25cf';
      const iconColor = eng.done ? '#4ade80' : eng.failed ? '#ef4444' : ec;
      const status = eng.status.length > 12 ? eng.status.slice(0, 12) + '\u2026' : eng.status;
      engineDots.push(
        <Text key={eng.id}>
          <Text color={iconColor}>{icon}</Text>
          <Text color={ec} bold>{eng.id}</Text>
          <Text dimColor>:{status} </Text>
        </Text>
      );
    }
  }

  // Stream snippet
  let snippetStr = '';
  if (streamSnippet) {
    const maxLen = 40;
    snippetStr = streamSnippet.line.length > maxLen ? streamSnippet.line.slice(0, maxLen) + '\u2026' : streamSnippet.line;
  }

  const scoreboardLines = scoreboard ? renderScoreboard(scoreboard) : '';
  const rationaleStr = rationale ? formatModeRationale(rationale) : '';

  return (
    <Box paddingTop={0} flexDirection="column">
      <Box>
        <Text>
          {hasPlan ? <><Text color={autoModeQueued ? '#f97316' : '#c084fc'} bold>{`\u25c8 ${planLabel.toUpperCase()}`}</Text><Text dimColor>{' \u2502 '}</Text></> : null}
          <Text color={cesarColor} bold>{'\u25c6 '}{cesarId}</Text>
          {confStr ? <Text color={confColor} bold>{confStr}</Text> : null}
          <Text dimColor>{' \u2502 '}</Text>
          <Text color="#fbbf24">{activityStr}</Text>
          {elapsedStr ? <Text dimColor>{elapsedStr}</Text> : null}
          {engineDots.length > 0 ? <Text dimColor>{' \u2502 '}</Text> : null}
        </Text>
        {engineDots.length > 0 && <Text>{engineDots}</Text>}
        <Text>
          {snippetStr ? <><Text dimColor>{' \u2502 '}</Text><Text dimColor wrap="truncate">{snippetStr}</Text></> : null}
        </Text>
      </Box>
      {planGauge.visible ? (
        <Text>
          <Text color={planGauge.color} bold>{'PLAN '}{planGauge.shortId}</Text>
          <Text dimColor>{' \u00b7 '}{planGauge.label}{' '}</Text>
          <Text color={planGauge.color}>{planGauge.bar}</Text>
          <Text dimColor>{' '}{planGauge.pct}{'% \u00b7 phase: '}{planGauge.phase}</Text>
          {planGauge.current ? <Text dimColor>{' \u00b7 '}{planGauge.current}</Text> : null}
          {planGauge.failed > 0 ? <Text color="#ef4444">{' \u00b7 '}{planGauge.failed}{' failed'}</Text> : null}
        </Text>
      ) : null}
      {rationaleStr ? <Text dimColor>{rationaleStr}</Text> : null}
      {scoreboardLines ? <Text dimColor>{scoreboardLines}</Text> : null}
    </Box>
  );
});
export { CesarStatusStrip };

